import { createThirdwebClient } from "thirdweb";

// Env vars are wired in LAST. A throwaway clientId keeps the
// ConnectButton rendering in demo mode without network calls.
const clientId =
  process.env.NEXT_PUBLIC_THIRDWEB_CLIENT_ID || "demo-client-id";

export const twClient = createThirdwebClient({ clientId });

// Placeholder — real Edition Drop / custom ERC-1155 address injected
// during the "refactor in smart contract + env vars" pass.
export const MEMBERSHIP_CONTRACT =
  process.env.NEXT_PUBLIC_MEMBERSHIP_CONTRACT || "0x0000000000000000000000000000000000000000";

import Stripe from "stripe";

let cached: Stripe | null = null;

export function getStripe(): Stripe | null {
  const key = process.env.STRIPE_SECRET_KEY;
  if (!key) return null; // demo mode — env vars come last
  if (!cached) {
    cached = new Stripe(key, { apiVersion: "2024-04-10" });
  }
  return cached;
}

export const DEMO_AMOUNT_CENTS = 999; // $9.99 membership

import { NextResponse } from "next/server";
import { getStripe, DEMO_AMOUNT_CENTS } from "@/lib/stripe";

export async function POST() {
  const stripe = getStripe();

  // Demo mode: no secret key yet → return a mock client secret so the
  // UI flow can be exercised end-to-end. Stripe.js will render the
  // Payment Element shell; confirm will no-op client-side.
  if (!stripe) {
    return NextResponse.json({
      clientSecret: "pi_demo_secret_demo",
      mode: "demo",
    });
  }

  const intent = await stripe.paymentIntents.create({
    amount: DEMO_AMOUNT_CENTS,
    currency: "usd",
    automatic_payment_methods: { enabled: true }, // surfaces Apple Pay / Google Pay
    metadata: { product: "membership" },
  });

  return NextResponse.json({ clientSecret: intent.client_secret });
}

import type { Metadata } from "next";
import "./globals.css";
