"use client";

import { ConnectButton } from "thirdweb/react";
import { createWallet, inAppWallet } from "thirdweb/wallets";
import { twClient } from "@/lib/thirdweb";

// Social login (Google / Apple / email) + self-custodial options.
// ThirdWeb's ConnectButton handles the embedded modal UX.
const wallets = [
  inAppWallet({
    auth: {
      options: ["google", "apple", "email", "passkey"],
    },
  }),
  createWallet("io.metamask"),
  createWallet("com.coinbase.wallet"),
  createWallet("me.rainbow"),
];

export function SignInButton() {
  return (
    <ConnectButton
      client={twClient}
      wallets={wallets}
      connectButton={{
        label: "Sign in",
        style: {
          fontFamily: '"Futura", "Futura PT", "Trebuchet MS", sans-serif',
          borderRadius: 0,
          padding: "10px 18px",
          fontSize: "14px",
        },
      }}
      connectModal={{
        title: "Sign in to continue reading",
        size: "compact",
        showThirdwebBranding: false,
      }}
      theme="light"
    />
  );
}

"use client";

import { useEffect, useState, type FormEvent } from "react";
import { loadStripe } from "@stripe/stripe-js";
import {
  Elements,
  PaymentElement,
  useElements,
  useStripe,
} from "@stripe/react-stripe-js";

const publishableKey = process.env.NEXT_PUBLIC_STRIPE_PUBLISHABLE_KEY;
const stripePromise = publishableKey ? loadStripe(publishableKey) : null;

// Brand appearance — Futura headings, Helvetica body, sharp corners.
const appearance = {
  theme: "stripe" as const,
  variables: {
    fontFamily: '"Helvetica Neue", Helvetica, Arial, sans-serif',
    fontSizeBase: "15px",
    colorPrimary: "#111111",
    colorText: "#111111",
    borderRadius: "2px",
  },
  rules: {
    ".Label": {
      fontFamily: '"Futura", "Futura PT", "Trebuchet MS", sans-serif',
      textTransform: "uppercase",
      letterSpacing: "0.05em",
      fontSize: "11px",
    },
    ".Tab": {
      fontFamily: '"Futura", "Futura PT", "Trebuchet MS", sans-serif',
    },
  },
};

interface Props {
  open: boolean;
  onClose: () => void;
  onSuccess: () => void;
}

export function StripeCheckoutModal({ open, onClose, onSuccess }: Props) {
  const [clientSecret, setClientSecret] = useState<string | null>(null);
  const [demoMode, setDemoMode] = useState(false);

  useEffect(() => {
    if (!open) return;
    fetch("/api/stripe/intent", { method: "POST" })
      .then((r) => r.json())
      .then((d) => {
        setClientSecret(d.clientSecret);
        setDemoMode(d.mode === "demo" || !stripePromise);
      });
  }, [open]);

  if (!open) return null;

  return (
    <div
      className="fixed inset-0 z-50 flex items-end sm:items-center justify-center bg-black/50 backdrop-blur-sm"
      onClick={onClose}
    >
      <div
        className="w-full sm:max-w-md bg-white p-6 sm:p-8 sm:rounded-sm shadow-2xl animate-in slide-in-from-bottom"
        onClick={(e) => e.stopPropagation()}
      >
        <div className="flex items-start justify-between mb-5">
          <div>
            <h2 className="font-title text-2xl tracking-tight">
              Unlimited access
            </h2>
            <p className="text-sm text-neutral-600 mt-1">
              $9.99 / month · cancel anytime
            </p>
          </div>
          <button
            onClick={onClose}
            className="text-neutral-400 hover:text-black text-xl leading-none"
            aria-label="Close"
          >
            ×
          </button>
        </div>

        {demoMode || !clientSecret || !stripePromise ? (
          <DemoPaymentForm onSuccess={onSuccess} />
        ) : (
          <Elements
            stripe={stripePromise}
            options={{ clientSecret, appearance }}
          >
            <LivePaymentForm onSuccess={onSuccess} />
          </Elements>
        )}

        <p className="text-[11px] text-neutral-400 mt-4 text-center">
          Apple&nbsp;Pay · Google&nbsp;Pay · Cards · Powered by Stripe
        </p>
      </div>
    </div>
  );
}

/* ---------- Live form (real Stripe keys) ---------- */

function LivePaymentForm({ onSuccess }: { onSuccess: () => void }) {
  const stripe = useStripe();
  const elements = useElements();
  const [busy, setBusy] = useState(false);
  const [err, setErr] = useState<string | null>(null);

  async function onSubmit(e: FormEvent) {
    e.preventDefault();
    if (!stripe || !elements) return;
    setBusy(true);
    setErr(null);

    const { error } = await stripe.confirmPayment({
      elements,
      redirect: "if_required",
    });

    setBusy(false);
    if (error) {
      setErr(error.message ?? "Payment failed");
    } else {
      onSuccess();
    }
  }

  return (
    <form onSubmit={onSubmit} className="space-y-5">
      {/* Apple Pay / Google Pay surface automatically via Payment Element wallets */}
      <PaymentElement
        options={{
          layout: "tabs",
          wallets: { applePay: "auto", googlePay: "auto" },
        }}
      />
      {err && <p className="text-sm text-red-600">{err}</p>}
      <button
        type="submit"
        disabled={busy}
        className="w-full bg-black text-white py-3 font-title tracking-wide disabled:opacity-50"
      >
        {busy ? "Processing…" : "Subscribe"}
      </button>
    </form>
  );
}

/* ---------- Demo form (no env vars yet) ---------- */

function DemoPaymentForm({ onSuccess }: { onSuccess: () => void }) {
  const [busy, setBusy] = useState(false);

  async function onSubmit(e: FormEvent) {
    e.preventDefault();
    setBusy(true);
    await new Promise((r) => setTimeout(r, 900));
    setBusy(false);
    onSuccess();
  }

  return (
    <form onSubmit={onSubmit} className="space-y-4">
      <div className="rounded-sm border border-neutral-200 p-3 space-y-3">
        <div className="flex gap-2">
          <button
            type="button"
            className="flex-1 border border-black py-2 text-xs font-title"
          >
             Pay
          </button>
          <button
            type="button"
            className="flex-1 border border-black py-2 text-xs font-title"
          >
            G Pay
          </button>
        </div>
        <div className="h-px bg-neutral-200" />
        <input
          placeholder="Card number"
          className="w-full border border-neutral-300 px-3 py-2 text-sm placeholder:text-neutral-400"
          defaultValue="4242 4242 4242 4242"
          readOnly
        />
        <div className="flex gap-2">
          <input
            placeholder="MM / YY"
            className="flex-1 border border-neutral-300 px-3 py-2 text-sm"
            defaultValue="12 / 34"
            readOnly
          />
          <input
            placeholder="CVC"
            className="flex-1 border border-neutral-300 px-3 py-2 text-sm"
            defaultValue="123"
            readOnly
          />
        </div>
        <p className="text-[10px] text-amber-600">
          Demo mode — add STRIPE keys to enable live Payment Element.
        </p>
      </div>
      <button
        type="submit"
        disabled={busy}
        className="w-full bg-black text-white py-3 font-title tracking-wide disabled:opacity-50"
      >
        {busy ? "Processing…" : "Subscribe (demo)"}
      </button>
    </form>
  );
}

"use client";

import { useState } from "react";
import { useActiveAccount } from "thirdweb/react";
import { SignInButton } from "./SignInButton";
import { StripeCheckoutModal } from "./StripeCheckoutModal";
import { MintMembership } from "./MintMembership";

interface PaywallProps {
  premium: boolean;
  children: React.ReactNode;
}

/**
 * NYT / WaPo-style paywall:
 *   • Article body renders underneath, clipped + gradient-faded.
 *   • Paywall card "rests" on top of the fade (not a full-screen blocker).
 *   • Stripe modal pops above it on "Subscribe".
 */
export function Paywall({ premium, children }: PaywallProps) {
  const account = useActiveAccount();
  const [unlocked, setUnlocked] = useState(false);
  const [checkoutOpen, setCheckoutOpen] = useState(false);

  const locked = premium && !unlocked;

  return (
    <>
      <div
        className={`relative ${locked ? "paywall-locked paywall-fade" : ""}`}
      >
        {children}

        {locked && (
          <div className="absolute inset-x-0 bottom-0 flex justify-center pb-4 px-4 z-10">
            <div className="max-w-xl w-full bg-white border border-neutral-200 shadow-[0_-8px_40px_rgba(0,0,0,0.12)] p-6 sm:p-8">
              <h3 className="font-title text-2xl sm:text-3xl mb-2">
                Keep reading this story.
              </h3>
              <p className="text-sm text-neutral-600 mb-6">
                Subscribe for unlimited access — or sign in if you already
                have a membership.
              </p>

              <div className="flex flex-col sm:flex-row gap-3">
                <button
                  onClick={() => setCheckoutOpen(true)}
                  className="flex-1 bg-black text-white py-3 font-title tracking-wide hover:bg-neutral-800"
                >
                  Subscribe — $9.99/mo
                </button>
                <div className="flex-1 flex justify-center">
                  <SignInButton />
                </div>
              </div>

              {account && (
                <div className="mt-5 pt-5 border-t border-neutral-200">
                  <MintMembership onMinted={() => setUnlocked(true)} />
                </div>
              )}

              <button
                onClick={() => setUnlocked(true)}
                className="mt-5 text-[11px] text-neutral-400 hover:text-neutral-600 underline"
              >
                Dev unlock (remove before ship)
              </button>
            </div>
          </div>
        )}
      </div>

      <StripeCheckoutModal
        open={checkoutOpen}
        onClose={() => setCheckoutOpen(false)}
        onSuccess={() => {
          setCheckoutOpen(false);
          setUnlocked(true);
        }}
      />
    </>
  );
}

"use client";

import { useState } from "react";
import { useActiveAccount } from "thirdweb/react";
import { MEMBERSHIP_CONTRACT } from "@/lib/thirdweb";

/**
 * Placeholder membership-NFT mint.
 *
 * Real flow (added in the env-var / contract refactor pass):
 *   import { getContract, sendTransaction } from "thirdweb";
 *   import { claimTo } from "thirdweb/extensions/erc1155";
 *   const contract = getContract({ client: twClient, chain, address: MEMBERSHIP_CONTRACT });
 *   const tx = claimTo({ contract, to: account.address, tokenId: 0n, quantity: 1n });
 *   await sendTransaction({ account, transaction: tx });
 */
export function MintMembership({ onMinted }: { onMinted: () => void }) {
  const account = useActiveAccount();
  const [busy, setBusy] = useState(false);

  const isPlaceholder =
    MEMBERSHIP_CONTRACT ===
    "0x0000000000000000000000000000000000000000";

  async function mint() {
    if (!account) return;
    setBusy(true);
    // TODO: swap to real claimTo() once contract is deployed.
    await new Promise((r) => setTimeout(r, 1200));
    setBusy(false);
    onMinted();
  }

  return (
    <div>
      <p className="text-xs text-neutral-500 mb-2">
        Connected as{" "}
        <span className="font-mono">
          {account?.address.slice(0, 6)}…{account?.address.slice(-4)}
        </span>
      </p>
      <button
        onClick={mint}
        disabled={busy}
        className="w-full border border-black py-2.5 font-title text-sm tracking-wide hover:bg-black hover:text-white disabled:opacity-50"
      >
        {busy ? "Minting…" : "Mint membership NFT"}
      </button>
      {isPlaceholder && (
        <p className="mt-2 text-[10px] text-amber-600">
          Contract not configured — demo mint (no on-chain tx).
        </p>
      )}
    </div>
  );
}

import { Paywall } from "@/components/Paywall";

// Mirrors a Sanity post with { premium: true }.
const demoPost = {
  title: "The Future of On-Chain Publishing",
  author: "Jane Developer",
  publishedAt: "March 19, 2026",
  premium: true,
  excerpt:
    "A new wave of creator tooling is collapsing the distance between a reader's wallet and a writer's byline. Here's what it means for independent publishing — and why the paywall of the future might be minted, not metered.",
  body: Array.from({ length: 8 }).map(
    (_, i) =>
      `Paragraph ${i + 1}. Lorem ipsum dolor sit amet, consectetur adipiscing elit. Sed do eiusmod tempor incididunt ut labore et dolore magna aliqua. Ut enim ad minim veniam, quis nostrud exercitation ullamco laboris nisi ut aliquip ex ea commodo consequat. Duis aute irure dolor in reprehenderit in voluptate velit esse cillum dolore eu fugiat nulla pariatur.`
  ),
};

export default function DemoPage() {
