"use client";

import { useState } from "react";
import { useActiveAccount } from "thirdweb/react";
import { SignInButton } from "./SignInButton";
import { StripeCheckoutModal } from "./StripeCheckoutModal";
import { MintMembership } from "./MintMembership";
import { useMembership } from "@/lib/useMembership";

interface PaywallProps {
  premium: boolean;
  children: React.ReactNode;
}

/**
 * Sequential paywall:
 *   1. Sign in (ThirdWeb wallet — social or self-custodial)
 *   2. Pay (Stripe fiat → server-mint, OR direct crypto mint)
 *   3. Unlocked (balanceOf > 0)
 *
 * The NFT is the membership. No users table.
 */
export function Paywall({ premium, children }: PaywallProps) {
  const account = useActiveAccount();
  const { hasMembership, loading, refresh } = useMembership(account?.address);
  const [checkoutOpen, setCheckoutOpen] = useState(false);
  const [devBypass, setDevBypass] = useState(false);

  const locked = premium && !hasMembership && !devBypass;

  return (
    <>
      <div
        className={`relative ${locked ? "paywall-locked paywall-fade" : ""}`}
      >
        {children}

        {locked && (
          <div className="absolute inset-x-0 bottom-0 flex justify-center pb-4 px-4 z-10">
            <div className="max-w-xl w-full bg-white border border-neutral-200 shadow-[0_-8px_40px_rgba(0,0,0,0.12)] p-6 sm:p-8">
              {!account ? (
                <SignInStep />
              ) : loading ? (
                <CheckingStep />
              ) : (
                <PayStep
                  address={account.address}
                  onCheckout={() => setCheckoutOpen(true)}
                  onMinted={refresh}
                />
              )}

              <button
                onClick={() => setDevBypass(true)}
                className="mt-5 text-[11px] text-neutral-400 hover:text-neutral-600 underline"
              >
                Dev unlock (remove before ship)
              </button>
            </div>
          </div>
        )}
      </div>

      {account && (
        <StripeCheckoutModal
          open={checkoutOpen}
          wallet={account.address}
          onClose={() => setCheckoutOpen(false)}
          onSuccess={() => {
            setCheckoutOpen(false);
            refresh();
          }}
        />
      )}
    </>
  );
}

/* ---------------- Step 1: sign in ---------------- */

function SignInStep() {
  return (
    <>
      <h3 className="font-title text-2xl sm:text-3xl mb-2">
        Sign in to keep reading.
      </h3>
      <p className="text-sm text-neutral-600 mb-6">
        Use Google, Apple, email, or your own wallet. Takes five seconds.
      </p>
      <div className="flex justify-center">
        <SignInButton />
      </div>
    </>
  );
}

/* ---------------- checking chain ---------------- */

function CheckingStep() {
  return (
    <div className="py-6 text-center">
      <p className="font-title text-sm tracking-wide text-neutral-500">
        Checking membership…
      </p>
    </div>
  );
}

/* ---------------- Step 2: pay ---------------- */

function PayStep({
  address,
  onCheckout,
  onMinted,
}: {
  address: string;
  onCheckout: () => void;
  onMinted: () => void;
}) {
  return (
    <>
      <h3 className="font-title text-2xl sm:text-3xl mb-1">
        One more step.
      </h3>
      <p className="text-xs font-mono text-neutral-400 mb-4">
        {address.slice(0, 6)}…{address.slice(-4)}
      </p>
      <p className="text-sm text-neutral-600 mb-6">
        Your membership is an NFT — pay with card or crypto, it lands in
        the same wallet.
      </p>

      <div className="space-y-3">
        <button
          onClick={onCheckout}
          className="w-full bg-black text-white py-3 font-title tracking-wide hover:bg-neutral-800"
        >
          Pay with card — $9.99
        </button>

        <div className="flex items-center gap-3 text-[10px] tracking-[0.2em] text-neutral-400">
          <span className="flex-1 h-px bg-neutral-200" />
          OR
          <span className="flex-1 h-px bg-neutral-200" />
        </div>

        <MintMembership onMinted={onMinted} />
      </div>
    </>
  );
}

