  children: React.ReactNode;
}

/**
 * NYT / WaPo-style paywall:
 *   • Article body renders underneath, clipped + gradient-faded.
 *   • Paywall card "rests" on top of the fade (not a full-screen blocker).
 *   • Stripe modal pops above it on "Subscribe".
 */
export function Paywall({ premium, children }: PaywallProps) {
  const account = useActiveAccount();
  const [unlocked, setUnlocked] = useState(false);
  const [checkoutOpen, setCheckoutOpen] = useState(false);

  const locked = premium && !unlocked;

  return (
    <>
      <div
        className={`relative ${locked ? "paywall-locked paywall-fade" : ""}`}
      >
        {children}

        {locked && (
          <div className="absolute inset-x-0 bottom-0 flex justify-center pb-4 px-4 z-10">
            <div className="max-w-xl w-full bg-white border border-neutral-200 shadow-[0_-8px_40px_rgba(0,0,0,0.12)] p-6 sm:p-8">
              <h3 className="font-title text-2xl sm:text-3xl mb-2">
                Keep reading this story.
              </h3>
              <p className="text-sm text-neutral-600 mb-6">
                Subscribe for unlimited access — or sign in if you already
                have a membership.
              </p>

              <div className="flex flex-col sm:flex-row gap-3">
                <button
                  onClick={() => setCheckoutOpen(true)}
                  className="flex-1 bg-black text-white py-3 font-title tracking-wide hover:bg-neutral-800"
                >
                  Subscribe — $9.99/mo
                </button>
                <div className="flex-1 flex justify-center">
                  <SignInButton />
                </div>
              </div>

              {account && (
                <div className="mt-5 pt-5 border-t border-neutral-200">
                  <MintMembership onMinted={() => setUnlocked(true)} />
                </div>
              )}

              <button
                onClick={() => setUnlocked(true)}
                className="mt-5 text-[11px] text-neutral-400 hover:text-neutral-600 underline"
              >
                Dev unlock (remove before ship)
              </button>
            </div>
          </div>
        )}
      </div>

      <StripeCheckoutModal
        open={checkoutOpen}
        onClose={() => setCheckoutOpen(false)}
        onSuccess={() => {
          setCheckoutOpen(false);
          setUnlocked(true);
        }}
      />
    </>
  );
}

