"use client";

import { useCallback, useEffect, useState } from "react";
import { getContract } from "thirdweb";
import { balanceOf } from "thirdweb/extensions/erc1155";
import { base } from "thirdweb/chains";
import { twClient, MEMBERSHIP_CONTRACT } from "./thirdweb";

const ZERO_ADDRESS = "0x0000000000000000000000000000000000000000";
const CONTRACT_CONFIGURED = MEMBERSHIP_CONTRACT !== ZERO_ADDRESS;

/**
 * On-chain membership check.
 * Source of truth = balanceOf(wallet, tokenId 0) on the ERC-1155.
 * Falls back to a session-level demo flag until the contract is deployed.
 */
export function useMembership(address: string | undefined) {
  const [hasMembership, setHasMembership] = useState(false);
  const [loading, setLoading] = useState(false);

  const refresh = useCallback(async () => {
    if (!address) {
      setHasMembership(false);
      return;
    }

    if (!CONTRACT_CONFIGURED) {
      // Demo mode — mint / Stripe success writes a sessionStorage flag.
      const flag = sessionStorage.getItem(`demo-member:${address}`);
      setHasMembership(flag === "1");
      return;
    }

    setLoading(true);
    try {
      const contract = getContract({
        client: twClient,
        chain: base,
        address: MEMBERSHIP_CONTRACT,
      });
      const bal = await balanceOf({
        contract,
        owner: address,
        tokenId: 0n,
      });
      setHasMembership(bal > 0n);
    } finally {
      setLoading(false);
    }
  }, [address]);

  useEffect(() => {
    void refresh();
  }, [refresh]);

  return { hasMembership, loading, refresh };
}

/** Demo-mode helper — grants membership locally when no contract exists. */
export function grantDemoMembership(address: string) {
  if (CONTRACT_CONFIGURED) return;
  sessionStorage.setItem(`demo-member:${address}`, "1");
}

