  return (
    <div>
      <p className="text-xs text-neutral-500 mb-2">
        Connected as{" "}
        <span className="font-mono">
          {account?.address.slice(0, 6)}…{account?.address.slice(-4)}
        </span>
      </p>
      <button
        onClick={mint}
        disabled={busy}
        className="w-full border border-black py-2.5 font-title text-sm tracking-wide hover:bg-black hover:text-white disabled:opacity-50"
      >
