 *   const tx = claimTo({ contract, to: account.address, tokenId: 0n, quantity: 1n });
 *   await sendTransaction({ account, transaction: tx });
 */
export function MintMembership({ onMinted }: { onMinted: () => void }) {
  const account = useActiveAccount();
  const [busy, setBusy] = useState(false);

  const isPlaceholder =
    MEMBERSHIP_CONTRACT ===
    "0x0000000000000000000000000000000000000000";

  async function mint() {
    if (!account) return;
    setBusy(true);
    // TODO: swap to real claimTo() once contract is deployed.
    await new Promise((r) => setTimeout(r, 1200));
    grantDemoMembership(account.address);
    setBusy(false);
    onMinted();
  }

  return (
    <div>
      <p className="text-xs text-neutral-500 mb-2">
        Connected as{" "}
        <span className="font-mono">
          {account?.address.slice(0, 6)}…{account?.address.slice(-4)}
        </span>
      </p>
      <button
        onClick={mint}
        disabled={busy}
        className="w-full border border-black py-2.5 font-title text-sm tracking-wide hover:bg-black hover:text-white disabled:opacity-50"
      >
        {busy ? "Minting…" : "Mint membership NFT"}
      </button>
      {isPlaceholder && (
        <p className="mt-2 text-[10px] text-amber-600">
          Contract not configured — demo mint (no on-chain tx).
        </p>
      )}
    </div>
  );
}

