import { NextRequest, NextResponse } from "next/server";
import Stripe from "stripe";
import { getStripe } from "@/lib/stripe";
import { mintMembershipTo } from "@/lib/membership-mint";

/**
 * Fiat on-ramp → NFT bridge.
 *
 * Stripe confirms payment → we server-mint the ERC-1155 to the wallet
 * that was stuffed into PaymentIntent.metadata before checkout.
 * No users table: the chain is the membership ledger.
 */
export async function POST(req: NextRequest) {
  const stripe = getStripe();
  const secret = process.env.STRIPE_WEBHOOK_SECRET;
  const sig = req.headers.get("stripe-signature");

  if (!stripe || !secret || !sig) {
    return NextResponse.json({ ok: true, mode: "demo" });
  }

  const raw = await req.text();
  let event: Stripe.Event;
  try {
    event = stripe.webhooks.constructEvent(raw, sig, secret);
  } catch (err) {
    return NextResponse.json(
      { error: `Signature verification failed: ${(err as Error).message}` },
      { status: 400 }
    );
  }

  if (event.type === "payment_intent.succeeded") {
    const pi = event.data.object as Stripe.PaymentIntent;
    const wallet = pi.metadata?.wallet;
    if (wallet) {
      await mintMembershipTo(wallet);
    }
  }

  return NextResponse.json({ received: true });
}

import { createThirdwebClient, getContract, sendTransaction } from "thirdweb";
import { claimTo } from "thirdweb/extensions/erc1155";
import { privateKeyToAccount } from "thirdweb/wallets";
import { base } from "thirdweb/chains";

/**
 * Server-side mint — called by the Stripe webhook after fiat payment.
 * Uses a backend wallet (private key) with the `MINTER` role on the
 * ERC-1155 Edition Drop.
 */
export async function mintMembershipTo(wallet: string): Promise<void> {
  const secretKey = process.env.THIRDWEB_SECRET_KEY;
  const minterKey = process.env.MEMBERSHIP_MINTER_PRIVATE_KEY;
  const address = process.env.NEXT_PUBLIC_MEMBERSHIP_CONTRACT;

  if (!secretKey || !minterKey || !address) {
    console.log(`[demo] would mint membership NFT to ${wallet}`);
    return;
  }

  const client = createThirdwebClient({ secretKey });
  const account = privateKeyToAccount({ client, privateKey: minterKey });
  const contract = getContract({ client, chain: base, address });

  const tx = claimTo({
    contract,
    to: wallet,
    tokenId: 0n,
    quantity: 1n,
  });

  await sendTransaction({ account, transaction: tx });
}

content.text:
Two viable architectures — pick based on how "Web3‑pure" you want to be.

---

## Option A: Stripe subscription → time-locked NFT (recommended)

Keep the NFT as source of truth but give it an **expiry**. Stripe's recurring engine just *extends* the expiry each cycle.

**Contract change** (ERC‑1155 with per-holder expiry, or swap to [ERC‑5643](https://eips.ethereum.org/EIPS/eip-5643) subscription NFT):
```solidity
mapping(address => uint256) public expiresAt;

function isActive(address holder) public view returns (bool) {
  return expiresAt[holder] > block.timestamp;
}

function extend(address holder, uint256 seconds_) external onlyMinter {
  uint256 base = expiresAt[holder] > block.timestamp
    ? expiresAt[holder]
    : block.timestamp;
  expiresAt[holder] = base + seconds_;
}
```

**Stripe side** — swap PaymentIntent for a Subscription:
```ts
// app/api/stripe/intent/route.ts
const sub = await stripe.subscriptions.create({
  customer: customerId,                     // create once per wallet
  items: [{ price: process.env.STRIPE_PRICE_ID }],
  payment_behavior: "default_incomplete",
  payment_settings: { save_default_payment_method: "on_subscription" },
  expand: ["latest_invoice.payment_intent"],
  metadata: { wallet },
});
return { clientSecret: sub.latest_invoice.payment_intent.client_secret };
```
Payment Element UX stays identical — Apple/Google Pay still surface.

**Webhook expands to three events:**
| Event | Action |
|---|---|
| `invoice.paid` | `contract.extend(wallet, 30 days)` |
| `customer.subscription.deleted` | nothing — NFT just expires naturally |
| `invoice.payment_failed` | optional: email, but NFT still valid until `expiresAt` |

**Paywall check** changes from `balanceOf > 0` to:
```ts
const expiry = await readContract({ contract, method: "expiresAt", params: [wallet] });
const unlocked = expiry > BigInt(Math.floor(Date.now() / 1000));
```

The only persistent mapping you need: **wallet → Stripe customerId**. Store it in the NFT's metadata or a tiny Vercel KV — it's 1 row per member, write-once.

---

## Option B: On-chain native recurring (no Stripe subscription)

- Use a streaming protocol (Superfluid, Sablier) — reader opens a USDC stream, paywall checks `stream.isActive(wallet)`
- Or monthly *re-mint*: NFT burns at expiry, reader re-claims (gas + crypto each month)

Cleaner architecturally but the UX tax is brutal for non-crypto readers. Fiat recurring ≈ always goes through Option A.

---

**My take:** Option A. Stripe handles card retry / dunning / Apple Pay sheets; chain holds membership truth via expiry timestamp. Best of both. Want me to refactor the intent route + webhook to subscription mode now, or keep one-time for the demo and branch later?

