}

/* NYT / WaPo style fade mask applied to article container */
.paywall-fade::after {
  content: "";
  position: absolute;
  inset-inline: 0;
  bottom: 0;
  height: 60%;
  background: linear-gradient(
    to bottom,
    rgba(255, 255, 255, 0) 0%,
    rgba(255, 255, 255, 0.95) 55%,
    #ffffff 100%
  );
  pointer-events: none;
}

.paywall-locked {
  max-height: 52vh;
  overflow: hidden;
}

